import java.util.*;

class Solution {
    public List<List<String>> findDuplicate(String[] paths) {
        Map<String, List<String>> contentMap = new HashMap<>();
        for (String path : paths) {
            String[] parts = path.split(" ");
            String directory = parts[0];
            for (int i = 1; i < parts.length; i++) {
                int openParenthesisIndex = parts[i].indexOf("(");
                String fileName = parts[i].substring(0, openParenthesisIndex);
                String content = parts[i].substring(openParenthesisIndex + 1, parts[i].length() - 1);
                String fullPath = directory + "/" + fileName;
                contentMap.computeIfAbsent(content, k -> new ArrayList<>()).add(fullPath);
            }
        }
        List<List<String>> result = new ArrayList<>();
        for (List<String> pathsList : contentMap.values()) {
            if (pathsList.size() > 1) {
                result.add(pathsList);
            }
        }
        return result;
    }
}
